EPHEMERAL_TICKS_GETTER_CREATION_
EPHEMERAL_TICKS_GETTER_

UNI_V3_POOL_ADDRESS=$1
RPC_URL=$2

if [ -z "$RPC_URL" ]; then
    echo "Error: RPC_URL is not set"
    exit 1
fi

if [ -z "$EPHEMERAL_TICKS_GETTER_BYTECODE" ]; then
    echo "Error: EPHEMERAL_TICKS_GETTER_BYTECODE is not set"
    exit 1
fi

REVERT_BYTES=$(cast call --rpc-url $RPC_URL --create $EPHEMERAL_TICKS_GETTER_BYTECODE 2>&1 | grep -o '0x[0-9a-fA-F]*' | head -n1)

echo $REVERT_BYTES

if [ -z "$REVERT_BYTES" ]; then
    echo "Error: got no revert bytes"
    exit 1
fi

cast decode-abi --json "f()((int24,uint128,int128)[])" $REVERT_BYTES | jq '.[]'